-- Table structure for ai_model_config
-- ----------------------------
DROP TABLE IF EXISTS `ai_model_config`;
CREATE TABLE `ai_model_config`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT,
  `model_id` int NOT NULL COMMENT '用户创建的AI 模型id',
  `temperature` float NOT NULL COMMENT '模型温度',
  `lexical` float NULL DEFAULT NULL COMMENT '词汇属性',
  `talk` float NULL DEFAULT NULL COMMENT '话题属性',
  `repeat` float NULL DEFAULT NULL COMMENT '重复属性',
  `tokens` int NULL DEFAULT NULL COMMENT '最大回复的token数',
  `timeout` int NULL DEFAULT NULL COMMENT '等待AI响应的最长时间，单位为秒。',
  `create_time` datetime NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  `update_time` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 5 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '用户自定义的 AI 模型高级配置，包含模型温度、最大回复等' ROW_FORMAT = Dynamic;

