-- ----------------------------
-- Table structure for chat_conversation
-- ----------------------------
DROP TABLE IF EXISTS `chat_conversation`;
CREATE TABLE `chat_conversation`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL,
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '对话标题',
  `last_active_time` datetime NULL DEFAULT NULL COMMENT '最后一次对话时间',
  `current_status` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '对话当前状态：NEW, ACTIVE,ENDED,FAILED',
  `create_time` datetime NOT NULL,
  `update_time` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `latest_conver_index`(`user_id` ASC, `last_active_time` DESC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'AI 聊天对话信息存储表' ROW_FORMAT = Dynamic;


-- ----------------------------
-- Table structure for chat_message_content
-- ----------------------------
DROP TABLE IF EXISTS `chat_message_content`;
CREATE TABLE `chat_message_content`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT,
  `cid` bigint UNSIGNED NOT NULL COMMENT '对话id',
  `mu_id` bigint NULL DEFAULT NULL COMMENT '用户单次对话id，关联 chat_message_user 表 id',
  `sender` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '消息发送者：AI，USER',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '消息内容',
  `content_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '消息类型：THINKING,CONTENT',
  `send_at` datetime NOT NULL COMMENT '消息发送时间',
  `metadata` json NULL COMMENT '元数据，token耗费等，业务决定具体细节',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `lastest_msg_index`(`cid` DESC, `send_at` DESC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'AI 回复消息存储表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for chat_message_thinking
-- ----------------------------
DROP TABLE IF EXISTS `chat_message_thinking`;
CREATE TABLE `chat_message_thinking`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT,
  `cid` bigint UNSIGNED NOT NULL COMMENT '对话id',
  `mu_id` bigint NOT NULL COMMENT '用户单次对话id，关联 chat_message_user 表 id',
  `sender` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '消息发送者：AI，USER',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '消息内容',
  `content_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '消息类型：THINKING,CONTENT',
  `send_at` datetime NOT NULL COMMENT '消息发送时间',
  `metadata` json NULL COMMENT '元数据，token耗费等，业务决定具体细节',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `lastest_msg_index`(`cid` DESC, `send_at` DESC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

